PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?id ?name ?city ?phone_number ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:City ?city .
  ?airports p:Phone_Number ?phone_number .
  ?airports p:Website ?website .
} }
  component_2: { SELECT ?id ?name ?state ?phone_number ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:State ?state .
  ?airports p:Phone_Number ?phone_number .
  ?airports p:Website ?website .
} }
  full: { SELECT ?id ?name ?city ?state ?phone_number ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:City ?city .
  ?airports p:State ?state .
  ?airports p:Phone_Number ?phone_number .
  ?airports p:Website ?website .
} }
}

PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?id ?name ?state ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:State ?state .
  ?airports p:Website ?website .
  ?airports p:Year_Established ?year_established_f .
  FILTER(xsd:double(?year_established_f) < 1950)
} }
  component_2: { SELECT ?id ?name ?city ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:City ?city .
  ?airports p:Website ?website .
  ?airports p:Year_Established ?year_established_f .
  FILTER(xsd:double(?year_established_f) < 1950)
} }
  full: { SELECT ?id ?name ?city ?state ?website WHERE {
  ?airports a :Airports .
  ?airports p:id ?id .
  ?airports p:name ?name .
  ?airports p:City ?city .
  ?airports p:State ?state .
  ?airports p:Website ?website .
  ?airports p:Year_Established ?year_established_f .
  FILTER(xsd:double(?year_established_f) < 1950)
} }
}
